evaluators.evaluation_logic:
const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const tickets = JSON.parse(localStorage.getItem('event_ticket_types') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');

function parseDate(v) {
  const d = new Date(v);
  return isNaN(d.getTime()) ? null : d;
}

// Determine next calendar month based on current date
const now = new Date();
const year = now.getUTCFullYear();
const month = now.getUTCMonth(); // 0-based
const nextMonthYear = month === 11 ? year + 1 : year;
const nextMonth = month === 11 ? 0 : month + 1;
const rangeStart = new Date(Date.UTC(nextMonthYear, nextMonth, 1, 0, 0, 0, 0));
const rangeEnd = new Date(Date.UTC(nextMonthYear, nextMonth + 1, 0, 23, 59, 59, 999));

// Find candidate in-person networking events in Chicago during that month
const candidateEvents = events.filter((e) => {
  if (e.status !== 'scheduled') return false;
  if (!e.city || String(e.city).toLowerCase() !== 'chicago') return false;
  if (e.is_virtual) return false;
  if (e.event_type !== 'networking') return false;
  const d = parseDate(e.start_datetime);
  if (!d) return false;
  return d >= rangeStart && d <= rangeEnd;
});

function getCheapestTicketUnderMax(eventId, maxPrice) {
  const tt = tickets.filter((t) => t.event_id === eventId && typeof t.price === 'number' && t.price <= maxPrice);
  if (!tt.length) return null;
  tt.sort((a, b) => a.price - b.price);
  return tt[0];
}

const maxPrice = 40;
let cheapestEvent = null;
let cheapestTicket = null;

candidateEvents.forEach((ev) => {
  const t = getCheapestTicketUnderMax(ev.id, maxPrice);
  if (!t) return;
  if (!cheapestTicket || t.price < cheapestTicket.price) {
    cheapestTicket = t;
    cheapestEvent = ev;
  }
});

let regsForCheapest = [];
let regsForCheapestAndYear = [];
let regsFullyCorrect = [];

if (cheapestEvent && cheapestTicket) {
  regsForCheapest = regs.filter(
    (r) => r.event_id === cheapestEvent.id && r.ticket_type_id === cheapestTicket.id && r.quantity >= 1
  );
  regsForCheapestAndYear = regsForCheapest.filter((r) => r.graduation_year === 2015);
  regsFullyCorrect = regsForCheapestAndYear.filter(
    (r) => String(r.industry || '').toLowerCase() === 'technology'
  );
}

// CP1 (0.4): Registered for the cheapest qualifying ticket of the correct event
checkpoints.push({ passed: regsForCheapest.length > 0, weight: 0.4 });
// CP2 (0.3): That registration records graduation year 2015
checkpoints.push({ passed: regsForCheapestAndYear.length > 0, weight: 0.3 });
// CP3 (0.3): That registration records industry = 'technology'
checkpoints.push({ passed: regsFullyCorrect.length > 0, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const funds = JSON.parse(localStorage.getItem('funds') || '[]');
const gifts = JSON.parse(localStorage.getItem('gifts') || '[]');

const scholarshipFunds = funds.filter((f) => {
  const code = String(f.code || '').toLowerCase();
  const name = String(f.name || '').toLowerCase();
  const desc = String(f.description || '').toLowerCase();
  return f.is_active && (code === 'student_scholarships' || name.includes('scholar') || desc.includes('scholar'));
});

const scholarshipFundIds = new Set(scholarshipFunds.map((f) => f.id));

const offlineMethods = ['bill_me_later', 'pay_by_mail', 'on_campus_billing', 'other_offline'];

// Gifts/pledges to the scholarships fund via offline non-card methods, not recurring
const baseGifts = gifts.filter((g) => {
  if (!scholarshipFundIds.has(g.fund_id)) return false;
  if (offlineMethods.indexOf(g.payment_method) === -1) return false;
  if (g.is_payment_completed_online) return false;
  if (g.gift_type === 'recurring_gift') return false;
  return true;
});

const correctAmountGifts = baseGifts.filter((g) => g.amount === 75);

function normalizeName(name) {
  return String(name || '').trim().toLowerCase();
}

const fullyCorrectGifts = correctAmountGifts.filter((g) => {
  if (g.tribute_type !== 'in_honor_of') return false;
  if (normalizeName(g.tribute_name) !== 'jordan lee') return false;
  return true;
});

// CP1 (0.3): Non-recurring offline gift/pledge made to a scholarships-designated fund
checkpoints.push({ passed: baseGifts.length > 0, weight: 0.3 });
// CP2 (0.3): Such a gift/pledge with the exact amount of $75
checkpoints.push({ passed: correctAmountGifts.length > 0, weight: 0.3 });
// CP3 (0.4): Such a gift/pledge marked as an 'in honor of' tribute specifically for Jordan Lee
checkpoints.push({ passed: fullyCorrectGifts.length > 0, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const topics = JSON.parse(localStorage.getItem('newsletter_topics') || '[]');
const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');
const subTopics = JSON.parse(localStorage.getItem('newsletter_subscription_topics') || '[]');

const topicById = {};
topics.forEach((t) => {
  topicById[t.id] = t;
});

function getTopicCodesForSubscription(subId) {
  const links = subTopics.filter((st) => st.subscription_id === subId);
  const codes = links
    .map((st) => (topicById[st.topic_id] && topicById[st.topic_id].code) || null)
    .filter(Boolean);
  return Array.from(new Set(codes));
}

const REQUIRED_CODES = ['career_services', 'alumni_events'];

const subsWithCorrectTopics = subs.filter((sub) => {
  if (sub.frequency !== 'monthly_digest') return false;
  if (!sub.consent_email_communications) return false;
  const codes = getTopicCodesForSubscription(sub.id);
  if (codes.length !== REQUIRED_CODES.length) return false;
  return REQUIRED_CODES.every((code) => codes.indexOf(code) !== -1);
});

const fullyCorrectSubs = subsWithCorrectTopics.filter((sub) => sub.email === 'sample.alum@example.com');

// CP1 (0.6): Subscription with monthly digest frequency and ONLY Career Services & Alumni Events topics
checkpoints.push({ passed: subsWithCorrectTopics.length > 0, weight: 0.6 });
// CP2 (0.4): Such a subscription uses the expected sample email address
checkpoints.push({ passed: fullyCorrectSubs.length > 0, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const chapters = JSON.parse(localStorage.getItem('chapters') || '[]');
const memberships = JSON.parse(localStorage.getItem('chapter_memberships') || '[]');

// Eligible CA chapters with membership fee <= 30 and active
const caChapters = chapters.filter((c) => {
  const state = String(c.state || '').toLowerCase();
  return state === 'ca' && c.is_active && typeof c.membership_fee === 'number' && c.membership_fee <= 30;
});

// Sort by upcoming_events_count desc, then name A-Z
caChapters.sort((a, b) => {
  const ea = typeof a.upcoming_events_count === 'number' ? a.upcoming_events_count : 0;
  const eb = typeof b.upcoming_events_count === 'number' ? b.upcoming_events_count : 0;
  if (ea !== eb) return eb - ea;
  const na = String(a.name || '').toLowerCase();
  const nb = String(b.name || '').toLowerCase();
  if (na < nb) return -1;
  if (na > nb) return 1;
  return 0;
});

const bestChapter = caChapters[0] || null;

let membershipsForBest = [];
let membershipsFullyCorrect = [];

if (bestChapter) {
  membershipsForBest = memberships.filter(
    (m) => m.chapter_id === bestChapter.id && m.role === 'alumni'
  );
  membershipsFullyCorrect = membershipsForBest.filter((m) => m.graduation_year === 2010);
}

// CP1 (0.6): Joined the correct California chapter as an alumnus/alumna
checkpoints.push({ passed: membershipsForBest.length > 0, weight: 0.6 });
// CP2 (0.4): That membership records graduation year 2010
checkpoints.push({ passed: membershipsFullyCorrect.length > 0, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const benefits = JSON.parse(localStorage.getItem('benefits') || '[]');
const savedBenefits = JSON.parse(localStorage.getItem('saved_benefits') || '[]');

const allowedCategories = new Set(['travel', 'travel_transportation']);

const eligibleBenefits = benefits.filter((b) => {
  if (!b.is_active) return false;
  if (!allowedCategories.has(b.category)) return false;
  if (typeof b.discount_percentage !== 'number' || b.discount_percentage < 10) return false;
  return true;
});

// Sort by discount_percentage desc, then name A-Z
eligibleBenefits.sort((a, b) => {
  const da = typeof a.discount_percentage === 'number' ? a.discount_percentage : 0;
  const db = typeof b.discount_percentage === 'number' ? b.discount_percentage : 0;
  if (da !== db) return db - da;
  const na = String(a.name || '').toLowerCase();
  const nb = String(b.name || '').toLowerCase();
  if (na < nb) return -1;
  if (na > nb) return 1;
  return 0;
});

const top1 = eligibleBenefits[0] || null;
const top2 = eligibleBenefits[1] || null;

function isSaved(benefit) {
  if (!benefit) return false;
  return savedBenefits.some((sb) => sb.benefit_id === benefit.id);
}

const savedTop1 = isSaved(top1);
const savedTop2 = isSaved(top2);

// CP1 (0.5): Saved the top (highest-discount) qualifying travel-related benefit
checkpoints.push({ passed: savedTop1, weight: 0.5 });
// CP2 (0.5): Also saved the second-highest qualifying travel-related benefit
checkpoints.push({ passed: savedTop2, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const profiles = JSON.parse(localStorage.getItem('alumni_profiles') || '[]');
const entries = JSON.parse(localStorage.getItem('contact_list_entries') || '[]');

// Eligible profiles: San Francisco, CA, software_engineering, grad 2010–2020 inclusive, visible
const eligibleProfiles = profiles.filter((p) => {
  const city = String(p.city || '').toLowerCase();
  const state = String(p.state || '').toLowerCase();
  const industry = String(p.industry || '').toLowerCase();
  const year = typeof p.graduation_year === 'number' ? p.graduation_year : null;
  if (city !== 'san francisco') return false;
  if (state !== 'ca') return false;
  if (industry !== 'software_engineering') return false;
  if (year == null || year < 2010 || year > 2020) return false;
  if (!p.is_visible_in_directory) return false;
  return true;
});

// Sort by last_name A–Z, then first_name
eligibleProfiles.sort((a, b) => {
  const la = String(a.last_name || '').toLowerCase();
  const lb = String(b.last_name || '').toLowerCase();
  if (la !== lb) return la < lb ? -1 : 1;
  const fa = String(a.first_name || '').toLowerCase();
  const fb = String(b.first_name || '').toLowerCase();
  if (fa < fb) return -1;
  if (fa > fb) return 1;
  return 0;
});

const targetProfiles = eligibleProfiles.slice(0, 3);
const targetIds = targetProfiles.map((p) => p.id);

const qualifyingEntries = entries.filter((e) => targetIds.indexOf(e.alumni_profile_id) !== -1);

// CP1 (0.3): Added at least one of the top three qualifying SF software engineering alumni to a contact list
checkpoints.push({ passed: qualifyingEntries.length >= 1, weight: 0.3 });
// CP2 (0.3): Added at least two of them
checkpoints.push({ passed: qualifyingEntries.length >= 2, weight: 0.3 });
// CP3 (0.4): Added all three of them
checkpoints.push({ passed: qualifyingEntries.length >= 3, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const programs = JSON.parse(localStorage.getItem('mentoring_programs') || '[]');
const topics = JSON.parse(localStorage.getItem('mentor_expertise_topics') || '[]');
const enrollments = JSON.parse(localStorage.getItem('mentor_enrollments') || '[]');
const enrollmentTopics = JSON.parse(localStorage.getItem('mentor_enrollment_expertise') || '[]');

const currentStudentPrograms = programs.filter((p) => p.audience === 'current_students' && p.is_active);
const programIds = new Set(currentStudentPrograms.map((p) => p.id));

const topicById = {};
topics.forEach((t) => {
  topicById[t.id] = t;
});

function getTopicCodesForEnrollment(enrollmentId) {
  const links = enrollmentTopics.filter((e) => e.mentor_enrollment_id === enrollmentId);
  const codes = links
    .map((l) => (topicById[l.expertise_topic_id] && topicById[l.expertise_topic_id].code) || null)
    .filter(Boolean);
  return Array.from(new Set(codes));
}

const baseEnrollments = enrollments.filter((e) => programIds.has(e.mentoring_program_id));

const meetingAndTimeEnrollments = baseEnrollments.filter(
  (e) => e.preferred_meeting_format === 'video_chat' && e.availability_hours_per_month === 2
);

const topicEnrollments = meetingAndTimeEnrollments.filter((e) => {
  const codes = getTopicCodesForEnrollment(e.id);
  return codes.indexOf('technology') !== -1 && codes.indexOf('entrepreneurship') !== -1;
});

const fullyCorrectEnrollments = topicEnrollments.filter(
  (e) => e.affiliation === 'alumnus_alumna' && e.graduation_year === 2008
);

// CP1 (0.4): Enrolled in an active program for current students with 2 hours/month via video chat
checkpoints.push({ passed: meetingAndTimeEnrollments.length > 0, weight: 0.4 });
// CP2 (0.3): Such enrollment has expertise topics including both technology and entrepreneurship
checkpoints.push({ passed: topicEnrollments.length > 0, weight: 0.3 });
// CP3 (0.3): Such enrollment is as an alumnus/alumna with graduation year 2008
checkpoints.push({ passed: fullyCorrectEnrollments.length > 0, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const scholarships = JSON.parse(localStorage.getItem('scholarships') || '[]');
const saved = JSON.parse(localStorage.getItem('saved_scholarships') || '[]');

function parseDate(v) {
  const d = new Date(v);
  return isNaN(d.getTime()) ? null : d;
}

const cutoff = new Date('2025-03-01T00:00:00Z');

const eligible = scholarships.filter((s) => {
  if (!s.is_active) return false;
  if (s.eligibility_group !== 'children_of_alumni') return false;
  if (s.level_of_study !== 'undergraduate') return false;
  const d = parseDate(s.deadline);
  if (!d || !(d > cutoff)) return false;
  return true;
});

function getMaxAward(s) {
  if (typeof s.award_amount_max === 'number') return s.award_amount_max;
  if (typeof s.award_amount === 'number') return s.award_amount;
  return 0;
}

eligible.sort((a, b) => getMaxAward(b) - getMaxAward(a));

const topScholarship = eligible[0] || null;

let savedTop = null;
if (topScholarship) {
  savedTop = saved.find((ss) => ss.scholarship_id === topScholarship.id) || null;
}

let noteIsDescriptive = false;
if (savedTop) {
  const note = String(savedTop.note || '').toLowerCase();
  const mentionsUndergrad = note.includes('undergrad') || note.includes('undergraduate');
  const mentionsChild =
    note.includes('child of alum') || note.includes('children of alumni') || note.includes('child of an alum');
  const mentionsDeadline =
    note.includes('post') || note.includes('after') || note.includes('3/1/2025') || note.includes('march 2025');
  noteIsDescriptive = mentionsUndergrad && mentionsChild && mentionsDeadline;
}

// CP1 (0.6): Saved the highest-award eligible scholarship matching the criteria
checkpoints.push({ passed: !!savedTop, weight: 0.6 });
// CP2 (0.4): The saved scholarship note indicates it's for an undergraduate child of an alum with a post–early 2025 deadline
checkpoints.push({ passed: !!savedTop && noteIsDescriptive, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
